mapper.update:
UPDATE t_voting_reminder_delivery
SET delivery_status = 4,
    failed_at = CURRENT_TIMESTAMP,
    last_error = #{lastError}
WHERE delivery_id = #{deliveryId}

mapper.select:
SELECT delivery_id, outbox_event_id, subject_id, tenant_id, building_id,
       opid, uid,
       CASE
           WHEN phone IS NULL OR length(phone) < 7 THEN phone
           ELSE CONCAT(substr(phone, 1, 3), '****', substr(phone, length(phone) - 3, 4))
       END AS phone,
       channel, message_template, message, delivery_status, attempts,
       created_at, last_attempt_at, submitted_at, confirmed_at, failed_at,
       provider_message_id, last_error
FROM t_voting_reminder_delivery
WHERE tenant_id = #{tenantId}
  AND subject_id = #{subjectId}

  AND building_id = #{buildingId}


  AND delivery_status = #{deliveryStatus}

ORDER BY created_at DESC, delivery_id DESC
LIMIT #{limit}
